// // This module implements an 8-bit synchronous counter that decrements instead of increments when the en signal is high.
module counter_8bit_sync_en(clk, rst, en, count);
    input clk;
    input rst;
    input en;
    output reg [7:0] count;

    always @(posedge clk) begin
        if (rst)
            count <= 8'b0;
        else if (en)
            count <= count + 1;
    end
endmodule
